var scrapers = [
  {county:'Brevard',wf:'scrape_brevard.yml'},
  {county:'Charlotte',wf:'scrape_charlotte.yml'},
  {county:'Highlands',wf:'scrape_highlands.yml'},
  {county:'Hillsborough',wf:'scrape_hillsborough.yml'},
  {county:'Indian River',wf:'scrape_indian_river.yml'},
  {county:'Lake',wf:'scrape_lake.yml'},
  {county:'Manatee',wf:'scrape_manatee.yml'},
  {county:'Martin',wf:'scrape_martin.yml'},
  {county:'Orange',wf:'scrape_orange.yml'},
  {county:'Osceola',wf:'scrape_osceola.yml'},
  {county:'Palm Beach',wf:'scrape_palm_beach.yml'},
  {county:'Pinellas',wf:'scrape_pinellas.yml'},
  {county:'Polk',wf:'scrape_polk.yml'},
  {county:'Sarasota',wf:'scrape_sarasota.yml'},
  {county:'Seminole',wf:'scrape_seminole.yml'}
];
var pat = env.get('GITHUB_PAT');
if (!pat) { msg.payload = '❌ GITHUB_PAT missing'; return msg; }
var delay = 0;
scrapers.forEach(function(s) {
  setTimeout(function() {
    node.send({
      headers: {'Authorization':'Bearer '+pat,'Accept':'application/vnd.github.v3+json','Content-Type':'application/json','User-Agent':'Shamrock-NodeRED'},
      url: 'https://api.github.com/repos/Shamrock2245/swfl-arrest-scrapers/actions/workflows/'+s.wf+'/dispatches',
      payload: JSON.stringify({ref:'main'}),
      _county: s.county
    });
  }, delay);
  delay += 10000;
});
msg.payload = '⏳ Triggering all 15 scrapers (10s stagger)...';
return msg;

var county = msg._county || 'All';
var code = msg.statusCode;
if (code === 204) {
  msg.payload = '✅ ' + county + ' triggered at ' + new Date().toLocaleTimeString('en-US',{timeZone:'America/New_York'});
} else {
  msg.payload = '❌ ' + county + ' failed (HTTP ' + code + ')';
}
return msg;

